import { PatternUnit } from '../../../type.js'
import { Rule } from '../../../rule/index.js'
import { functionHeaderToPattern } from './common.js'
import { DeclareEvent } from '../../../../../node/event.js'
import { Evaluable, Expression, Identifier } from '../../../../../node/base.js'
import { Token } from '../../../../tokenize/token.js'

const PREFIX: PatternUnit[] = [
    {
        type: Identifier,
        value: '이벤트',
    },
    {
        type: Expression,
        value: '(',
    },
    {
        type: Evaluable,
    },
    {
        type: Expression,
        value: ')',
    },
    {
        type: Expression,
        value: ',',
    },
]

export function tokensToEventDeclareRule(headerTokens: Token[]): Rule {
    const pattern = [
        ...PREFIX,
        ...functionHeaderToPattern(headerTokens.slice(6)),
    ]

    return {
        pattern,
        factory: (nodes, matchedTokens) => {
            const eventId = (nodes[2] as Identifier).value
            const name = headerTokens
                .map((token) => token.value)
                .join('')
                .trim()

            return new DeclareEvent(
                {
                    name,
                    eventId,
                },
                matchedTokens,
            )
        },
    }
}
